queries.sparql:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?interest_rate WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasLoan_Programs ?child ; p:hasHousing_Finance_Agencies ?parent . } GROUP BY ?child }
  ?child p:interest_rate ?interest_rate .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Housing_Finance_Agencies } }
  FILTER(?nf = ?total)
}

